import SwiftUI
import SwiftData

struct ResultsView: View { let summary: GameSessionSummary; @EnvironmentObject private var store: StoreService; @Environment(\.modelContext) private var modelContext; @Query private var shares: [ExportRecord]; @State private var shareURL: URL?; var body: some View { ZStack { NeonBackground(); VStack(spacing:20) { Text(summary.didWin ? "Dare complete" : "Round done").font(.largeTitle.bold()); StarsView(count:summary.stars); Text(summary.score.pointsText).font(.system(size:54, weight:.black)); Text(summary.challenge.title).foregroundStyle(NeonTheme.softText); NeonCTA(title:"Share scorecard", icon:"square.and.arrow.up") { share() } }.padding(28) }.sheet(item:Binding(get:{ shareURL.map(URLBox.init(url:)) }, set:{ _ in shareURL=nil })) { box in ShareSheet(items:[box.url]) } }; private func share() { let limiter = ExportLimiter(); guard limiter.canShare(isPro:store.isPro, usedToday:limiter.countToday(shares)) else { return }; if let url = ScorecardRenderer.make(summary:summary, waterMark:!store.isPro) { modelContext.insert(ExportRecord(sessionID:summary.id)); shareURL=url } } }
struct URLBox: Identifiable { let id = UUID(); let url: URL }
